solution_code:
#include <iostream>
#include <vector>

std::vector<int> makeRepeated(int count, int value)
{
    return std::vector<int>(count, value);
}

int main()
{
    int count, value;
    std::cin >> count >> value;

    std::vector<int> result = makeRepeated(count, value);

    for (int i = 0; i < static_cast<int>(result.size()); ++i)
    {
        if (i > 0)
            std::cout << ' ';
        std::cout << result[i];
    }
    std::cout << '\n';

    return 0;
}
